const raw = $input.first().json.text || $input.first().json.content || '';
let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch(e) {
  parsed = { sentiment: 'neutral', response: raw };
}
return [{ json: { sentiment: parsed.sentiment, aiResponse: parsed.response } }];
